DROP MATERIALIZED VIEW "public"."order_stats";--> statement-breakpoint
CREATE MATERIALIZED VIEW "public"."order_stats" AS (select "users"."id" as "customer_id", "users"."name", count(distinct "orders"."id") as "total_orders", sum("order_items"."price" * "order_items"."quantity") as "total_spend", avg("order_items"."price"  * "order_items"."quantity") as "avg_order_value", max("orders"."created_at") as "last_order_at" from "users" left join "orders" on "orders"."customer_id" = "users"."id" left join "order_items" on "order_items"."order_id" = "orders"."id" group by "users"."id", "users"."name");